 182	function mergeConfig(base: RayaConfig, raw: unknown): RayaConfig {
 183	  if (!isRecord(raw)) {
 184	    return base;
 185	  }
 186	
 187	  const search = isRecord(raw.search) ? raw.search : undefined;
 188	  const images = isRecord(raw.images) ? raw.images : undefined;
 189	  const retries = isRecord(raw.retries) ? raw.retries : undefined;
 190	  const openrouter = isRecord(raw.openrouter) ? raw.openrouter : undefined;
 191	  const mode = raw.mode === "Agent" || raw.mode === "Chat" ? raw.mode : base.mode;
 192	  const apiKey = optionalString(openrouter?.apiKey) ?? base.openrouter.apiKey;
 193	
 194	  return {
 195	    ...base,
 196	    model: optionalString(raw.model) ?? base.model,
 197	    models: optionalStringArray(raw.models) ?? base.models,
 198	    mode,
 199	    contextTokens: optionalNumber(raw.contextTokens) ?? base.contextTokens,
 200	    search: {
 201	      ...base.search,
 202	      maxResults: optionalNumber(search?.maxResults) ?? base.search.maxResults,
 203	      pageChars: optionalNumber(search?.pageChars) ?? base.search.pageChars,
 204	      fetchTimeoutMs: optionalNumber(search?.fetchTimeoutMs) ?? base.search.fetchTimeoutMs
 205	    },
 206	    images: {
 207	      ...base.images,
 208	      maxDimension: optionalNumber(images?.maxDimension) ?? base.images.maxDimension,
 209	      jpegQuality: optionalNumber(images?.jpegQuality) ?? base.images.jpegQuality
 210	    },
 211	    retries: {
 212	      ...base.retries,
 213	      maxAttempts: optionalNumber(retries?.maxAttempts) ?? base.retries.maxAttempts,
 214	      initialDelayMs: optionalNumber(retries?.initialDelayMs) ?? base.retries.initialDelayMs
 215	    },
 216	    openrouter: {
 217	      ...base.openrouter,
 218	      ...(apiKey ? { apiKey } : {}),
 219	      baseURL: optionalString(openrouter?.baseURL) ?? base.openrouter.baseURL,
 220	      referer: optionalString(openrouter?.referer) ?? base.openrouter.referer,
 221	      title: optionalString(openrouter?.title) ?? base.openrouter.title
 222	    }
 223	  };
 224	}
