 482	async function fetchWithTimeout(url: string, timeoutMs: number): Promise<Response> {
 483	  const controller = new AbortController();
 484	  const timeout = setTimeout(() => controller.abort(), timeoutMs);
 485	
 486	  try {
 487	    return await fetch(url, {
 488	      signal: controller.signal,
 489	      headers: {
 490	        "User-Agent": "Raya/0.1 (+https://github.com/haos/raya-agent)",
 491	        Accept: "text/html, text/plain;q=0.9, */*;q=0.8"
 492	      }
 493	    });
 494	  } finally {
 495	    clearTimeout(timeout);
 496	  }
 497	}
