 499	async function fetchPage(result: SearchResult): Promise<WebPage> {
 500	  try {
 501	    const response = await fetchWithTimeout(result.url, searchFetchTimeoutMs);
 502	
 503	    if (!response.ok) {
 504	      return { ...result, text: "", fetched: false, error: `${response.status} ${response.statusText}` };
 505	    }
 506	
 507	    const contentType = response.headers.get("content-type") ?? "";
 508	
 509	    if (!contentType.includes("text/html") && !contentType.includes("text/plain")) {
 510	      return { ...result, text: "", fetched: false, error: `Unsupported content type: ${contentType || "unknown"}` };
 511	    }
 512	
 513	    const body = await response.text();
 514	    const text = stripHtml(body).slice(0, pageContentLimit);
 515	
 516	    return { ...result, text, fetched: text.length > 0 };
 517	  } catch (error) {
 518	    const message = error instanceof Error ? error.message : String(error);
 519	    return { ...result, text: "", fetched: false, error: message };
 520	  }
 521	}
 522	
 523	async function fetchPages(results: SearchResult[]): Promise<WebPage[]> {
 524	  return Promise.all(results.map((result) => fetchPage(result)));
 525	}
