 527	async function searchWeb(query: string): Promise<SearchResult[]> {
 528	  const url = new URL("https://html.duckduckgo.com/html/");
 529	  url.searchParams.set("q", query);
 530	
 531	  const response = await fetch(url, {
 532	    headers: {
 533	      "User-Agent": "Raya/0.1 (+https://github.com/haos/raya-agent)",
 534	      Accept: "text/html"
 535	    }
 536	  });
 537	
 538	  if (!response.ok) {
 539	    throw new Error(`Search failed: ${response.status} ${response.statusText}`);
 540	  }
 541	
 542	  const html = await response.text();
 543	  const resultBlocks = html.match(/<div class="result[\s\S]*?<\/div>\s*<\/div>/g) ?? [];
 544	
 545	  return resultBlocks
 546	    .map((block): SearchResult | undefined => {
 547	      const linkMatch = block.match(/<a[^>]+class="result__a"[^>]+href="([^"]+)"[^>]*>([\s\S]*?)<\/a>/);
 548	      const snippetMatch = block.match(/<a[^>]+class="result__snippet"[^>]*>([\s\S]*?)<\/a>|<div[^>]+class="result__snippet"[^>]*>([\s\S]*?)<\/div>/);
 549	
 550	      if (!linkMatch) {
 551	        return undefined;
 552	      }
 553	
 554	      return {
 555	        title: decodeHtml(linkMatch[2] ?? ""),
 556	        url: unwrapDuckDuckGoUrl(linkMatch[1] ?? ""),
 557	        snippet: decodeHtml(snippetMatch?.[1] ?? snippetMatch?.[2] ?? "")
 558	      };
