 564	async function clipboardImageToDataUrl(): Promise<string> {
 565	  const directory = await mkdtemp(join(tmpdir(), "raya-clipboard-"));
 566	  const pngPath = join(directory, "clipboard.png");
 567	  const jpegPath = join(directory, "clipboard.jpg");
 568	  const script = `
 569	ObjC.import('AppKit');
 570	const imagePath = ${JSON.stringify(pngPath)};
 571	const pasteboard = $.NSPasteboard.generalPasteboard;
 572	const image = $.NSImage.alloc.initWithPasteboard(pasteboard);
 573	if (!image) {
 574	  throw new Error('Clipboard does not contain an image.');
 575	}
 576	const tiffData = image.TIFFRepresentation;
 577	if (!tiffData) {
 578	  throw new Error('Could not read clipboard image data.');
 579	}
 580	const bitmap = $.NSBitmapImageRep.imageRepWithData(tiffData);
 581	if (!bitmap) {
 582	  throw new Error('Could not convert clipboard image data.');
 583	}
 584	const pngData = bitmap.representationUsingTypeProperties(4, $());
 585	if (!pngData || !pngData.writeToFileAtomically(imagePath, true)) {
 586	  throw new Error('Could not save clipboard image as PNG.');
 587	}
 588	`;
 589	
 590	  try {
 591	    await execFileAsync("osascript", ["-l", "JavaScript", "-e", script], { timeout: 10000 });
 592	    await execFileAsync(
 593	      "sips",
 594	      ["-Z", String(imageMaxDimension), "-s", "format", "jpeg", "-s", "formatOptions", String(imageJpegQuality), pngPath, "--out", jpegPath],
 595	      { timeout: 10000 }
 596	    );
 597	    const image = await readFile(jpegPath);
 598	    return `data:image/jpeg;base64,${image.toString("base64")}`;
 599	  } catch (error) {
 600	    const message = error instanceof Error ? error.message : String(error);
 601	    throw new Error(`Clipboard image failed: ${message}`);
 602	  } finally {
 603	    await rm(directory, { recursive: true, force: true });
 604	  }
 605	}
